# test_moving_average.py

import pytest

# Replace `your_module` with the actual module name where moving_average is defined.
from your_module import moving_average


@pytest.mark.parametrize(
    "data, window, expected",
    [
        ([1, 2, 3, 4, 5], 3, [2.0, 3.0, 4.0]),
        ([10, 20, 30, 40], 2, [15.0, 25.0, 35.0]),
        ([5, 10, 15], 1, [5.0, 10.0, 15.0]),
        ([2, 4, 6, 8], 4, [5.0]),
        ([1.5, 2.5, 3.5], 2, [2.0, 3.0]),
        ([-1, -2, -3, -4], 2, [-1.5, -2.5, -3.5]),
    ],
)
def test_moving_average_happy_paths(data, window, expected):
    assert moving_average(data, window) == pytest.approx(expected)


@pytest.mark.parametrize(
    "data, window",
    [
        ([1, 2, 3], 0),
        ([1, 2, 3], -1),
        ([1, 2, 3], 4),
        ([], 1),
        ([], 0),
    ],
)
def test_moving_average_invalid_window_returns_empty_list(data, window):
    assert moving_average(data, window) == []


def test_moving_average_empty_data_with_negative_window_returns_empty_list():
    assert moving_average([], -5) == []


def test_moving_average_single_element_window_one():
    assert moving_average([42], 1) == [42.0]


def test_moving_average_single_element_window_too_large():
    assert moving_average([42], 2) == []


def test_moving_average_preserves_input_data():
    data = [1, 2, 3, 4]
    original = data.copy()

    moving_average(data, 2)

    assert data == original


@pytest.mark.parametrize(
    "data, window",
    [
        ([1, "2", 3], 2),
        ([None, 1, 2], 2),
    ],
)
def test_moving_average_non_numeric_data_raises_type_error(data, window):
    with pytest.raises(TypeError):
        moving_average(data, window)


@pytest.mark.parametrize(
    "data, window",
    [
        ([1, 2, 3], "2"),
        ([1, 2, 3], None),
        ([1, 2, 3], 2.5),
    ],
)
def test_moving_average_invalid_window_type_raises_type_error(data, window):
    with pytest.raises(TypeError):
        moving_average(data, window)


def test_moving_average_none_data_raises_type_error():
    with pytest.raises(TypeError):
        moving_average(None, 2)
